import { useComposableList } from '../../hooks/composable'

interface Contact {
  id: string
  name: string
  email: string
  company: string
  status: 'lead' | 'active' | 'churned'
}

const STATUS_COLORS: Record<Contact['status'], string> = {
  lead: 'bg-yellow-100 text-yellow-800',
  active: 'bg-green-100 text-green-800',
  churned: 'bg-red-100 text-red-800',
}

interface ContactListProps {
  componentId: string
  listenToComponent?: string
  items?: Contact[]
}

export function ContactList({ componentId, listenToComponent, items: initialItems }: ContactListProps) {
  const {
    items,
    selectedIndex,
    emitSelection,
    filterQuery,
  } = useComposableList<Contact>({
    componentId,
    listenToComponent,
    initialItems: initialItems ?? [
      { id: '1', name: 'Sarah Chen', email: 'sarah@acme.co', company: 'Acme Corp', status: 'active' },
      { id: '2', name: 'James Wilson', email: 'james@globex.com', company: 'Globex', status: 'lead' },
      { id: '3', name: 'Maria Garcia', email: 'maria@initech.io', company: 'Initech', status: 'active' },
      { id: '4', name: 'Alex Kim', email: 'alex@umbrella.dev', company: 'Umbrella', status: 'churned' },
      { id: '5', name: 'Pat Johnson', email: 'pat@waystar.com', company: 'Waystar', status: 'lead' },
    ],
    filterFn: (contact, query) =>
      contact.name.toLowerCase().includes(query.toLowerCase()) ||
      contact.email.toLowerCase().includes(query.toLowerCase()) ||
      contact.company.toLowerCase().includes(query.toLowerCase()),
  })

  return (
    <div className="flex flex-col gap-1">
      <div className="text-xs font-medium text-gray-500 uppercase tracking-wide px-3 py-2">
        Contacts ({items.length})
      </div>
      {items.map((contact, index) => (
        <button
          key={contact.id}
          onClick={() => emitSelection(contact, index)}
          className={`w-full text-left px-3 py-2 rounded-lg transition-colors ${
            selectedIndex === index
              ? 'bg-blue-50 border border-blue-200'
              : 'hover:bg-gray-50'
          }`}
        >
          <div className="flex items-center justify-between">
            <div>
              <div className="text-sm font-medium text-gray-900">{contact.name}</div>
              <div className="text-xs text-gray-500">{contact.email}</div>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-xs text-gray-400">{contact.company}</span>
              <span className={`text-xs px-1.5 py-0.5 rounded-full ${STATUS_COLORS[contact.status]}`}>
                {contact.status}
              </span>
            </div>
          </div>
        </button>
      ))}
      {items.length === 0 && (
        <div className="text-sm text-gray-400 text-center py-8">
          {filterQuery ? 'No contacts match your search' : 'No contacts yet'}
        </div>
      )}
    </div>
  )
}
